class Solution {
    public int countCharacters(String[] words, String chars) {
        int[] charsCount = countChars(chars);
        int sum = 0;
        for (String word : words) {
            if (canFormWord(word, charsCount)) {
                sum += word.length();
            }
        }
        return sum;
    }

    private int[] countChars(String str) {
        int[] count = new int[26];
        for (char c : str.toCharArray()) {
            count[c - 'a']++;
        }
        return count;
    }

    private boolean canFormWord(String word, int[] charsCount) {
        int[] wordCount = countChars(word);
        for (int i = 0; i < 26; i++) {
            if (wordCount[i] > charsCount[i]) {
                return false;
            }
        }
        return true;
    }
}
